package main

import (
	"context"
	"fmt"
	"log"
	"net"
	"os"
	"os/signal"
	"syscall"
	"time"

	"google.golang.org/grpc"
	"google.golang.org/grpc/health"
	"google.golang.org/grpc/health/grpc_health_v1"
	"google.golang.org/grpc/reflection"
)

type Config struct {
	Port                  string
	ReflectionEnabled     bool
	ReflectionEnvOverride string
}

func getConfig() *Config {
	port := os.Getenv("GRPC_PORT")
	if port == "" {
		port = "50051"
	}

	reflectionEnabled := true
	env := os.Getenv("ENVIRONMENT")
	if env == "production" || env == "prod" {
		reflectionOverride := os.Getenv("ENABLE_REFLECTION")
		if reflectionOverride == "false" || reflectionOverride == "0" {
			reflectionEnabled = false
			log.Println("WARNING: gRPC reflection is disabled in production via ENABLE_REFLECTION override")
		} else {
			log.Println("SECURITY WARNING: gRPC reflection is enabled in production environment")
			log.Println("This exposes service metadata and method signatures publicly")
			log.Println("Set ENABLE_REFLECTION=false to disable reflection in production")
		}
	}

	return &Config{
		Port:                  port,
		ReflectionEnabled:     reflectionEnabled,
		ReflectionEnvOverride: env,
	}
}

type ExampleServiceServer struct {
	UnimplementedExampleServiceServer
}

func (s *ExampleServiceServer) SayHello(ctx context.Context, req *HelloRequest) (*HelloResponse, error) {
	return &HelloResponse{
		Message: fmt.Sprintf("Hello, %s!", req.Name),
	}, nil
}

func (s *ExampleServiceServer) GetServerInfo(ctx context.Context, req *ServerInfoRequest) (*ServerInfoResponse, error) {
	return &ServerInfoResponse{
		Version:   "1.0.0",
		Timestamp: time.Now().Unix(),
	}, nil
}

func main() {
	config := getConfig()

	lis, err := net.Listen("tcp", fmt.Sprintf(":%s", config.Port))
	if err != nil {
		log.Fatalf("Failed to listen: %v", err)
	}

	grpcServer := grpc.NewServer()

	exampleService := &ExampleServiceServer{}
	RegisterExampleServiceServer(grpcServer, exampleService)

	healthServer := health.NewServer()
	grpc_health_v1.RegisterHealthServer(grpcServer, healthServer)
	healthServer.SetServingStatus("", grpc_health_v1.HealthCheckResponse_SERVING)
	healthServer.SetServingStatus("ExampleService", grpc_health_v1.HealthCheckResponse_SERVING)

	if config.ReflectionEnabled {
		reflection.Register(grpcServer)
		log.Printf("gRPC reflection enabled - services discoverable via grpcurl or similar tools")
	}

	log.Printf("Starting gRPC server on port %s", config.Port)
	log.Printf("Environment: %s", config.ReflectionEnvOverride)
	log.Printf("Reflection enabled: %v", config.ReflectionEnabled)

	go func() {
		if err := grpcServer.Serve(lis); err != nil {
			log.Fatalf("Failed to serve: %v", err)
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	log.Println("Shutting down gRPC server...")
	grpcServer.GracefulStop()
	log.Println("Server stopped")
}